import{_ as s,o as i,c as o,a2 as t}from"./chunks/framework.DtwafDNl.js";const u=JSON.parse('{"title":"SIP Extensions","description":"","frontmatter":{},"headers":[],"relativePath":"features/extensions.md","filePath":"features/extensions.md"}'),n={name:"features/extensions.md"};function a(r,e,l,p,h,c){return i(),o("div",null,[...e[0]||(e[0]=[t('<h1 id="sip-extensions" tabindex="-1">SIP Extensions <a class="header-anchor" href="#sip-extensions" aria-label="Permalink to &quot;SIP Extensions&quot;">​</a></h1><p>SIP Extensions are the user and device registrations used by softphones, desk phones, and operator workflows. Callytics provisions extensions from the database so you can manage users and endpoint settings from the browser.</p><p>For quick softphone setup, extensions can provide a QR code compatible with Linphone-style onboarding. Teams that want stronger remote-access controls can mark selected extensions as VPN-only, requiring those devices to register through the private WireGuard network.</p><p>Extension status is visible in diagnostics, making it easier to confirm whether a phone is registered and reachable. The same extensions can also be used by operators when logging into queues from their softphones.</p><h2 id="webrtc-extensions" tabindex="-1">WebRTC extensions <a class="header-anchor" href="#webrtc-extensions" aria-label="Permalink to &quot;WebRTC extensions&quot;">​</a></h2><p>WebRTC extensions are meant for the built-in browser softphone, not Zoiper or Linphone registration.</p><ul><li>The SIP URI shown for a WebRTC extension is reference information only.</li><li>Registration for WebRTC extensions happens through the browser softphone.</li><li>QR provisioning is not available for WebRTC extensions.</li></ul><h2 id="capabilities" tabindex="-1">Capabilities <a class="header-anchor" href="#capabilities" aria-label="Permalink to &quot;Capabilities&quot;">​</a></h2><ul><li>Database-backed PJSIP extension provisioning</li><li>QR code for Linphone-compatible auto-provisioning</li><li>VPN-only restriction toggle</li><li>Extension registration status in diagnostics</li><li>Softphone support</li><li>Operator login flow support</li></ul>',9)])])}const b=s(n,[["render",a]]);export{u as __pageData,b as default};
